import React, { useState } from "react";

const FIELDS = [
  "SUMMARY",
  "EDUCATION",
  "COMPETENCIES",
  "EXPERIENCE",
  "PROJECTS",
  "CERTS"
];

export default function App() {
  const [field, setField] = useState("SUMMARY");
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [backendUrl, setBackendUrl] = useState("http://localhost:4000");

  async function handleGenerateWithAI(e) {
    e.preventDefault();
    setLoading(true);
    try {
      // 1. Ask backend AI to generate content for the selected section
      const aiResponse = await fetch(`${backendUrl}/api/generate`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          description: text,
          fields: [field]
        })
      });
      const aiFields = await aiResponse.json();
      if (!aiResponse.ok || !aiFields[field]) {
        alert('Error: ' + (aiFields.error || 'No content generated!'));
        setLoading(false);
        return;
      }

      // 2. Inject that generated content into the template and generate the PDF
      const pdfResponse = await fetch(`${backendUrl}/api/inject`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          replacements: { [field]: aiFields[field] }
        }),
      });

      if (!pdfResponse.ok) {
        const err = await pdfResponse.json();
        alert("Error: " + (err.error || JSON.stringify(err)));
        setLoading(false);
        return;
      }

      const blob = await pdfResponse.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "custom_resume.pdf";
      a.click();
      URL.revokeObjectURL(url);

    } catch (err) {
      alert("Network error: " + err.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ padding: 20, fontFamily: "Arial, sans-serif", maxWidth: 800, margin: "auto" }}>
      <h2>Auto Resume Builder — AI Section Generator</h2>
      <p>Paste a <b>job description</b> or <b>requirements</b> below,<br />
         select which resume section you want to fill (e.g., SUMMARY),<br />
         and let AI generate that section for you. The result will be downloaded as a PDF.</p>

      <div style={{ marginBottom: 8 }}>
        <label>Backend URL: </label>
        <input value={backendUrl} onChange={e => setBackendUrl(e.target.value)} style={{ width: 300 }} />
        <small style={{ marginLeft: 8, color: "#666" }}>e.g. http://localhost:4000</small>
      </div>

      <div style={{ marginBottom: 8 }}>
        <label>Field: </label>
        <select value={field} onChange={e => setField(e.target.value)}>
          {FIELDS.map(f => <option key={f} value={f}>{f}</option>)}
        </select>
      </div>

      <form onSubmit={handleGenerateWithAI}>
        <textarea
          value={text}
          onChange={e => setText(e.target.value)}
          rows={12}
          style={{ width: "100%", padding: 8 }}
          placeholder="Paste the job description or requirements. The AI will analyze and generate a tailored section for your resume."
          required
        />
        <div style={{ marginTop: 10 }}>
          <button type="submit" disabled={loading || !text.trim()}>{loading ? "Generating..." : "Generate PDF"}</button>
        </div>
      </form>
    </div>
  );
}
